import{_ as a,o as t,c as o,a2 as i}from"./chunks/framework.BFZItJIV.js";const u=JSON.parse('{"title":"Roadmap","description":"Planned and in-progress features for TalaDB — ordered by impact and priority.","frontmatter":{"title":"Roadmap","description":"Planned and in-progress features for TalaDB — ordered by impact and priority."},"headers":[],"relativePath":"roadmap.md","filePath":"roadmap.md"}'),r={name:"roadmap.md"};function n(s,e,d,l,c,p){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#roadmap" aria-label="Permalink to &quot;Roadmap&quot;">​</a></h1><p>This page tracks planned and in-progress work for TalaDB. Sections and items are ordered by estimated impact — things at the top affect the most users and unblock the most use cases.</p><p>Have an idea or want to help prioritise? Open a <a href="https://github.com/thinkgrid-labs/taladb/discussions" target="_blank" rel="noreferrer">GitHub Discussion</a> or a feature request issue.</p><hr><h2 id="_1-·-developer-experience" tabindex="-1">1 · Developer experience <a class="header-anchor" href="#_1-·-developer-experience" aria-label="Permalink to &quot;1 · Developer experience&quot;">​</a></h2><p>Better DX drives adoption and reduces time-to-production.</p><h3 id="http-push-sync" tabindex="-1">HTTP push sync <a class="header-anchor" href="#http-push-sync" aria-label="Permalink to &quot;HTTP push sync&quot;">​</a></h3><p><strong>Future extensions</strong> of this feature (not in scope for initial release):</p><ul><li>Native NoSQL adapters (<code>sync.adapter: mongodb | firestore | dynamodb</code>) with direct connection strings, removing the need for an intermediate API</li><li>Bi-directional pull: <code>taladb sync --pull</code> fetches from the remote and merges locally</li><li>Per-collection sync config (sync some collections, skip others)</li></ul><h3 id="taladb-studio-—-local-web-ui" tabindex="-1"><code>taladb studio</code> — local web UI <a class="header-anchor" href="#taladb-studio-—-local-web-ui" aria-label="Permalink to &quot;`taladb studio` — local web UI&quot;">​</a></h3><p>A browser-based GUI (served by <code>taladb-cli</code>) for browsing collections, running ad-hoc queries, inspecting indexes, and visualising query plans — similar to MongoDB Compass but for local files.</p><h3 id="zod-valibot-schema-validation" tabindex="-1">Zod / Valibot schema validation <a class="header-anchor" href="#zod-valibot-schema-validation" aria-label="Permalink to &quot;Zod / Valibot schema validation&quot;">​</a></h3><p>An optional <code>schema</code> option on <code>collection()</code> that validates documents with a Zod or Valibot schema before insert and after find, providing runtime type safety without a compile step.</p><h3 id="taladb-generate-—-typescript-type-generation" tabindex="-1"><code>taladb generate</code> — TypeScript type generation <a class="header-anchor" href="#taladb-generate-—-typescript-type-generation" aria-label="Permalink to &quot;`taladb generate` — TypeScript type generation&quot;">​</a></h3><p>Inspect a live database and emit TypeScript interfaces for each collection, inferred from the stored documents. Useful for projects that don&#39;t start with a schema.</p><h3 id="vs-code-extension" tabindex="-1">VS Code extension <a class="header-anchor" href="#vs-code-extension" aria-label="Permalink to &quot;VS Code extension&quot;">​</a></h3><p>Syntax highlighting for TalaDB filter expressions in JSON, inline document previews, and a collection browser panel in the VS Code sidebar.</p><hr><h2 id="_2-·-advanced-sync" tabindex="-1">2 · Advanced sync <a class="header-anchor" href="#_2-·-advanced-sync" aria-label="Permalink to &quot;2 · Advanced sync&quot;">​</a></h2><p>Multi-device and collaborative data sync beyond simple API push.</p><h3 id="conflict-free-sync-with-crdts" tabindex="-1">Conflict-free sync with CRDTs <a class="header-anchor" href="#conflict-free-sync-with-crdts" aria-label="Permalink to &quot;Conflict-free sync with CRDTs&quot;">​</a></h3><p>A <code>CrdtSyncAdapter</code> that uses per-field logical clocks (LWW-register or grow-only sets) to merge concurrent writes from multiple devices without conflicts — suitable for collaborative offline-first apps.</p><h3 id="delta-snapshots" tabindex="-1">Delta snapshots <a class="header-anchor" href="#delta-snapshots" aria-label="Permalink to &quot;Delta snapshots&quot;">​</a></h3><p>Instead of exporting the full database on every sync, export only the records that changed since a given ULID watermark — reducing bandwidth for incremental sync scenarios. Foundation for the sync server below.</p><h3 id="sync-over-websockets" tabindex="-1">Sync over WebSockets <a class="header-anchor" href="#sync-over-websockets" aria-label="Permalink to &quot;Sync over WebSockets&quot;">​</a></h3><p>A reference sync server (<code>taladb-sync-server</code>) that accepts snapshot diffs over a WebSocket connection and applies <code>LastWriteWins</code> or CRDT merge logic server-side, enabling multi-device sync without a cloud database.</p><hr><h2 id="_3-·-storage" tabindex="-1">3 · Storage <a class="header-anchor" href="#_3-·-storage" aria-label="Permalink to &quot;3 · Storage&quot;">​</a></h2><p>Internal improvements that improve efficiency and interoperability.</p><h3 id="write-ahead-log-compaction" tabindex="-1">Write-ahead log compaction <a class="header-anchor" href="#write-ahead-log-compaction" aria-label="Permalink to &quot;Write-ahead log compaction&quot;">​</a></h3><p>redb already handles WAL compaction internally, but exposing a <code>db.compact()</code> API for explicit compaction (e.g. after bulk deletes) would let long-running applications reclaim disk space on demand.</p><h3 id="pluggable-serialisation" tabindex="-1">Pluggable serialisation <a class="header-anchor" href="#pluggable-serialisation" aria-label="Permalink to &quot;Pluggable serialisation&quot;">​</a></h3><p>Allow the caller to swap <code>postcard</code> for <code>MessagePack</code> or <code>CBOR</code> via a <code>Codec</code> trait, making it easier to interoperate with databases or wire formats that already use those encodings.</p><hr><h2 id="_4-·-platform" tabindex="-1">4 · Platform <a class="header-anchor" href="#_4-·-platform" aria-label="Permalink to &quot;4 · Platform&quot;">​</a></h2><p>Expanding the runtimes TalaDB can target.</p><h3 id="cloudflare-workers-deno-deploy" tabindex="-1">Cloudflare Workers / Deno Deploy <a class="header-anchor" href="#cloudflare-workers-deno-deploy" aria-label="Permalink to &quot;Cloudflare Workers / Deno Deploy&quot;">​</a></h3><p>A <code>StorageBackend</code> implementation backed by Cloudflare&#39;s <code>KV</code> or <code>Durable Objects</code> API, letting TalaDB run as the persistence layer inside an edge function with zero external dependencies.</p><h3 id="bun-native-module" tabindex="-1">Bun native module <a class="header-anchor" href="#bun-native-module" aria-label="Permalink to &quot;Bun native module&quot;">​</a></h3><p>A Bun-native binding (using Bun&#39;s <code>bun:ffi</code>) that avoids the N-API layer for better startup performance and smaller binary size in Bun-first projects.</p><h3 id="swift-kotlin-native-packages" tabindex="-1">Swift / Kotlin native packages <a class="header-anchor" href="#swift-kotlin-native-packages" aria-label="Permalink to &quot;Swift / Kotlin native packages&quot;">​</a></h3><p>First-party Swift (<code>TalaDB.swift</code>) and Kotlin (<code>taladb-kotlin</code>) packages that wrap the C FFI layer directly, without React Native, for native iOS and Android apps that want an embedded document store.</p><h3 id="wasi-target" tabindex="-1">WASI target <a class="header-anchor" href="#wasi-target" aria-label="Permalink to &quot;WASI target&quot;">​</a></h3><p>Compile <code>taladb-core</code> to WASI (<code>wasm32-wasip1</code>) so it can run inside WASI runtimes (Wasmtime, WasmEdge, Fastly Compute) with filesystem access — bringing the same engine to server-side WASM environments.</p><hr><h2 id="_5-·-security" tabindex="-1">5 · Security <a class="header-anchor" href="#_5-·-security" aria-label="Permalink to &quot;5 · Security&quot;">​</a></h2><p>Hardening for apps that handle sensitive data.</p><h3 id="key-rotation" tabindex="-1">Key rotation <a class="header-anchor" href="#key-rotation" aria-label="Permalink to &quot;Key rotation&quot;">​</a></h3><p>A <code>db.rekey(newKey)</code> method that re-encrypts all stored values in a single atomic transaction without requiring an export/import cycle.</p><h3 id="field-level-encryption" tabindex="-1">Field-level encryption <a class="header-anchor" href="#field-level-encryption" aria-label="Permalink to &quot;Field-level encryption&quot;">​</a></h3><p>Encrypt individual fields rather than entire values, so that unencrypted fields can still be indexed and used in range queries while sensitive fields (e.g. <code>ssn</code>, <code>creditCard</code>) are protected at rest.</p><h3 id="audit-log" tabindex="-1">Audit log <a class="header-anchor" href="#audit-log" aria-label="Permalink to &quot;Audit log&quot;">​</a></h3><p>An append-only <code>_audit</code> collection that records every write operation (collection, document ID, operation type, timestamp) — opt-in, with configurable retention.</p>',53)])])}const m=a(r,[["render",n]]);export{u as __pageData,m as default};
